// Enhanced Detection Agent Logic
const item = $input.first();
const content = item.json.content;
const domain = item.json.domain;
const contentId = item.json.content_id;

// Multi-dimensional quality analysis
const qualityMetrics = {
  readability: 0,
  engagement: 0,
  accuracy: 0,
  uniqueness: 0,
  structure: 0,
  domain_relevance: 0
};

// Readability Analysis
function analyzeReadability(text) {
  const sentences = text.split(/[.!?]+/).filter(s => s.trim().length > 0);
  const words = text.split(/\s+/).filter(w => w.length > 0);
  const avgWordsPerSentence = words.length / sentences.length;

  // Flesch-Kincaid approximation
  const avgSyllables = words.reduce((sum, word) => {
    return sum + Math.max(1, word.toLowerCase().match(/[aeiouy]+/g)?.length || 1);
  }, 0) / words.length;

  const fleschScore = 206.835 - (1.015 * avgWordsPerSentence) - (84.6 * avgSyllables);

  return {
    score: Math.max(0, Math.min(100, fleschScore)),
    avg_words_per_sentence: avgWordsPerSentence,
    avg_syllables: avgSyllables,
    total_words: words.length,
    total_sentences: sentences.length
  };
}

// Engagement Analysis
function analyzeEngagement(text, domain) {
  const engagementWords = {
    finance: ['growth', 'opportunity', 'potential', 'analysis', 'insight', 'strategy', 'performance', 'investment'],
    sports: ['exciting', 'dramatic', 'incredible', 'outstanding', 'victory', 'championship', 'record', 'performance'],
    technology: ['innovative', 'breakthrough', 'cutting-edge', 'revolutionary', 'advanced', 'future', 'development', 'solution'],
    general: ['important', 'significant', 'valuable', 'effective', 'successful', 'beneficial', 'essential', 'outstanding']
  };

  const domainWords = engagementWords[domain] || engagementWords.general;
  const textLower = text.toLowerCase();

  let engagementScore = 0;
  domainWords.forEach(word => {
    const matches = (textLower.match(new RegExp(word, 'g')) || []).length;
    engagementScore += matches * 5;
  });

  // Check for questions, lists, and calls to action
  const questions = (text.match(/\?/g) || []).length;
  const lists = (text.match(/^\s*[•-]|^\s*\d+\./gm) || []).length;
  const actionWords = (textLower.match(/\b(discover|learn|find|explore|understand|consider)\b/g) || []).length;

  engagementScore += questions * 3 + lists * 2 + actionWords * 2;

  return {
    score: Math.min(100, engagementScore),
    engagement_words_count: domainWords.filter(word => textLower.includes(word)).length,
    questions: questions,
    lists: lists,
    action_words: actionWords
  };
}

// Structure Analysis
function analyzeStructure(text) {
  const paragraphs = text.split(/\n\s*\n/).filter(p => p.trim().length > 0);
  const headers = (text.match(/^#{1,6}\s+.+$/gm) || []).length;
  const sentences = text.split(/[.!?]+/).filter(s => s.trim().length > 0);

  let structureScore = 0;

  // Paragraph length analysis
  const avgParagraphLength = paragraphs.reduce((sum, p) => sum + p.split(/[.!?]+/).length, 0) / paragraphs.length;
  if (avgParagraphLength >= 3 && avgParagraphLength <= 6) structureScore += 25;

  // Header usage
  if (headers > 0) structureScore += 20;
  if (headers >= paragraphs / 3) structureScore += 10;

  // Introduction and conclusion detection
  const firstParagraph = paragraphs[0] || '';
  const lastParagraph = paragraphs[paragraphs.length - 1] || '';

  if (firstParagraph.length > 100) structureScore += 15;
  if (lastParagraph.toLowerCase().includes('conclusion') || 
      lastParagraph.toLowerCase().includes('summary') ||
      lastParagraph.toLowerCase().includes('in summary')) {
    structureScore += 15;
  }

  // Logical flow indicators
  const transitionWords = ['however', 'therefore', 'moreover', 'furthermore', 'additionally', 'consequently'];
  const transitionCount = transitionWords.reduce((sum, word) => {
    return sum + (text.toLowerCase().match(new RegExp('\\b' + word + '\\b', 'g')) || []).length;
  }, 0);

  structureScore += Math.min(15, transitionCount * 3);

  return {
    score: Math.min(100, structureScore),
    paragraphs: paragraphs.length,
    headers: headers,
    avg_paragraph_length: avgParagraphLength,
    transition_words: transitionCount
  };
}

// Domain Relevance Analysis
function analyzeDomainRelevance(text, domain) {
  const domainTerms = {
    finance: ['market', 'stock', 'investment', 'trading', 'economy', 'financial', 'revenue', 'profit', 'loss', 'capital', 'asset', 'portfolio', 'dividend', 'earnings', 'debt', 'equity'],
    sports: ['team', 'player', 'game', 'match', 'season', 'championship', 'league', 'score', 'victory', 'defeat', 'tournament', 'coach', 'athlete', 'performance', 'statistics'],
    technology: ['software', 'hardware', 'application', 'system', 'platform', 'digital', 'innovation', 'development', 'programming', 'algorithm', 'data', 'artificial intelligence', 'machine learning', 'cloud']
  };

  const terms = domainTerms[domain] || [];
  if (terms.length === 0) return { score: 70, relevant_terms: 0 };

  const textLower = text.toLowerCase();
  let relevantTermCount = 0;

  terms.forEach(term => {
    if (textLower.includes(term.toLowerCase())) {
      relevantTermCount++;
    }
  });

  const relevanceScore = Math.min(100, (relevantTermCount / terms.length) * 100 + 30);

  return {
    score: relevanceScore,
    relevant_terms: relevantTermCount,
    total_terms: terms.length
  };
}

// Pattern Detection for AI-Generated Content
function detectAIPatterns(text) {
  const aiIndicators = [
    /\bin conclusion\b/gi,
    /\bit's important to note\b/gi,
    /\bit's worth noting\b/gi,
    /\bas an ai\b/gi,
    /\bin summary\b/gi,
    /\boverall\b.*\bit can be said\b/gi,
    /\bthe key takeaway\b/gi,
    /\bto summarize\b/gi
  ];

  let patternCount = 0;
  aiIndicators.forEach(pattern => {
    const matches = text.match(pattern);
    if (matches) patternCount += matches.length;
  });

  // Check for repetitive sentence structures
  const sentences = text.split(/[.!?]+/).filter(s => s.trim().length > 0);
  const sentenceStarts = sentences.map(s => s.trim().split(' ').slice(0, 3).join(' ').toLowerCase());
  const uniqueStarts = new Set(sentenceStarts);
  const repetitionRatio = 1 - (uniqueStarts.size / sentenceStarts.length);

  return {
    ai_pattern_count: patternCount,
    repetition_ratio: repetitionRatio,
    uniqueness_score: Math.max(0, 100 - (patternCount * 10 + repetitionRatio * 50))
  };
}

// Perform all analyses
const readabilityAnalysis = analyzeReadability(content);
const engagementAnalysis = analyzeEngagement(content, domain);
const structureAnalysis = analyzeStructure(content);
const domainRelevanceAnalysis = analyzeDomainRelevance(content, domain);
const patternAnalysis = detectAIPatterns(content);

// Calculate weighted scores
qualityMetrics.readability = readabilityAnalysis.score * 0.2;
qualityMetrics.engagement = engagementAnalysis.score * 0.25;
qualityMetrics.structure = structureAnalysis.score * 0.2;
qualityMetrics.domain_relevance = domainRelevanceAnalysis.score * 0.15;
qualityMetrics.uniqueness = patternAnalysis.uniqueness_score * 0.2;

// Overall quality score
const overallScore = Object.values(qualityMetrics).reduce((sum, score) => sum + score, 0);

// Generate improvement suggestions
const suggestions = [];

if (readabilityAnalysis.score < 60) {
  suggestions.push('Simplify sentence structure and use shorter sentences for better readability');
}

if (engagementAnalysis.score < 50) {
  suggestions.push(`Add more ${domain}-specific engaging language and actionable insights`);
}

if (structureAnalysis.score < 60) {
  suggestions.push('Improve article structure with better headers, paragraphs, and logical flow');
}

if (domainRelevanceAnalysis.score < 70) {
  suggestions.push(`Include more ${domain}-specific terminology and concepts`);
}

if (patternAnalysis.uniqueness_score < 70) {
  suggestions.push('Reduce repetitive patterns and AI-like phrases to improve content uniqueness');
}

if (patternAnalysis.ai_pattern_count > 3) {
  suggestions.push('Remove obvious AI-generated phrases and improve natural language flow');
}

// Generate detailed feedback
const detailedFeedback = {
  overall_score: Math.round(overallScore * 100) / 100,
  quality_metrics: qualityMetrics,
  detailed_analysis: {
    readability: readabilityAnalysis,
    engagement: engagementAnalysis,
    structure: structureAnalysis,
    domain_relevance: domainRelevanceAnalysis,
    pattern_detection: patternAnalysis
  },
  suggestions: suggestions,
  quality_level: overallScore >= 85 ? 'excellent' : overallScore >= 75 ? 'good' : overallScore >= 60 ? 'acceptable' : 'needs_improvement'
};

return [{
  json: {
    content_id: contentId,
    domain: domain,
    quality_score: Math.round(overallScore * 100) / 100,
    feedback: detailedFeedback,
    analysis_timestamp: new Date().toISOString(),
    detection_agent_version: '2.0'
  }
}];

// Advanced Adversarial Generation Strategy
const item = $input.first();
const feedback = item.json.feedback;
const contentId = item.json.content_id;
const domain = item.json.domain;

// Analyze specific weaknesses
const qualityMetrics = feedback.quality_metrics || {};
const detailedAnalysis = feedback.detailed_analysis || {};

// Generate targeted improvement strategies
const improvementStrategies = [];

// Readability improvements
if (qualityMetrics.readability < 15) { // Out of 20 points
  const readabilityData = detailedAnalysis.readability || {};
  if (readabilityData.avg_words_per_sentence > 20) {
    improvementStrategies.push({
      category: 'readability',
      strategy: 'sentence_length',
      instruction: 'Break down complex sentences. Aim for 12-18 words per sentence on average.',
      priority: 'high'
    });
  }

  if (readabilityData.avg_syllables > 1.6) {
    improvementStrategies.push({
      category: 'readability',
      strategy: 'vocabulary_simplification',
      instruction: 'Use simpler vocabulary. Replace complex words with more accessible alternatives.',
      priority: 'medium'
    });
  }
}

// Engagement improvements
if (qualityMetrics.engagement < 20) { // Out of 25 points
  const engagementData = detailedAnalysis.engagement || {};

  if (engagementData.questions < 2) {
    improvementStrategies.push({
      category: 'engagement',
      strategy: 'add_questions',
      instruction: 'Include 2-3 thought-provoking questions to engage readers.',
      priority: 'high'
    });
  }

  if (engagementData.lists === 0) {
    improvementStrategies.push({
      category: 'engagement',
      strategy: 'add_lists',
      instruction: 'Use bullet points or numbered lists to break down complex information.',
      priority: 'medium'
    });
  }

  improvementStrategies.push({
    category: 'engagement',
    strategy: 'domain_specific_language',
    instruction: `Use more engaging ${domain}-specific language that resonates with the target audience.`,
    priority: 'high'
  });
}

// Structure improvements
if (qualityMetrics.structure < 16) { // Out of 20 points
  const structureData = detailedAnalysis.structure || {};

  if (structureData.headers < 3) {
    improvementStrategies.push({
      category: 'structure',
      strategy: 'add_headers',
      instruction: 'Add descriptive section headers to improve article structure and readability.',
      priority: 'high'
    });
  }

  if (structureData.avg_paragraph_length > 7) {
    improvementStrategies.push({
      category: 'structure',
      strategy: 'paragraph_length',
      instruction: 'Break long paragraphs into smaller, more digestible sections (3-5 sentences each).',
      priority: 'medium'
    });
  }

  if (structureData.transition_words < 3) {
    improvementStrategies.push({
      category: 'structure',
      strategy: 'transition_words',
      instruction: 'Add transition words and phrases to improve logical flow between sections.',
      priority: 'low'
    });
  }
}

// Domain relevance improvements
if (qualityMetrics.domain_relevance < 12) { // Out of 15 points
  const domainData = detailedAnalysis.domain_relevance || {};

  improvementStrategies.push({
    category: 'domain_relevance',
    strategy: 'increase_terminology',
    instruction: `Include more ${domain}-specific terminology and concepts. Current coverage: ${domainData.relevant_terms}/${domainData.total_terms} terms.`,
    priority: 'high'
  });

  // Domain-specific improvements
  if (domain === 'finance') {
    improvementStrategies.push({
      category: 'domain_relevance',
      strategy: 'financial_context',
      instruction: 'Add specific financial metrics, market context, and economic implications.',
      priority: 'high'
    });
  } else if (domain === 'sports') {
    improvementStrategies.push({
      category: 'domain_relevance',
      strategy: 'sports_context',
      instruction: 'Include relevant statistics, player/team performance data, and competitive context.',
      priority: 'high'
    });
  } else if (domain === 'technology') {
    improvementStrategies.push({
      category: 'domain_relevance',
      strategy: 'tech_context',
      instruction: 'Add technical specifications, industry trends, and innovation implications.',
      priority: 'high'
    });
  }
}

// Uniqueness improvements
if (qualityMetrics.uniqueness < 16) { // Out of 20 points
  const patternData = detailedAnalysis.pattern_detection || {};

  if (patternData.ai_pattern_count > 2) {
    improvementStrategies.push({
      category: 'uniqueness',
      strategy: 'remove_ai_patterns',
      instruction: 'Remove obvious AI-generated phrases and clichés. Write more naturally and conversationally.',
      priority: 'high'
    });
  }

  if (patternData.repetition_ratio > 0.3) {
    improvementStrategies.push({
      category: 'uniqueness',
      strategy: 'vary_sentence_structure',
      instruction: 'Vary sentence structure and opening phrases to improve content uniqueness.',
      priority: 'medium'
    });
  }
}

// Generate adversarial prompt modifications
const adversarialInstructions = {
  writing_style: {
    natural_flow: 'Write in a natural, conversational tone that flows organically from one idea to the next.',
    avoid_ai_phrases: 'Avoid phrases like "it\'s important to note", "in conclusion", "the key takeaway", and other AI-typical expressions.',
    vary_structure: 'Vary your sentence structure and paragraph openings to create a unique writing pattern.'
  },
  content_depth: {
    specific_examples: 'Include specific, concrete examples rather than general statements.',
    data_integration: 'Integrate relevant data points and statistics naturally into the narrative.',
    expert_perspective: 'Write from an expert perspective with insider knowledge and nuanced understanding.'
  },
  engagement_tactics: {
    hook_opening: 'Start with a compelling hook that immediately captures reader interest.',
    strategic_questions: 'Ask strategic questions that make readers think critically about the topic.',
    actionable_insights: 'Provide actionable insights that readers can immediately apply or consider.'
  }
};

// Sort strategies by priority
improvementStrategies.sort((a, b) => {
  const priorityOrder = { 'high': 3, 'medium': 2, 'low': 1 };
  return priorityOrder[b.priority] - priorityOrder[a.priority];
});

// Generate improvement prompt
let improvementPrompt = '\n\nADVERSARIAL IMPROVEMENT INSTRUCTIONS:\n';
improvementPrompt += '===========================================\n\n';

improvementPrompt += `QUALITY ANALYSIS RESULTS:\n`;
improvementPrompt += `- Overall Score: ${feedback.overall_score}/100 (${feedback.quality_level})\n`;
improvementPrompt += `- Readability: ${Math.round(qualityMetrics.readability)}/20\n`;
improvementPrompt += `- Engagement: ${Math.round(qualityMetrics.engagement)}/25\n`;
improvementPrompt += `- Structure: ${Math.round(qualityMetrics.structure)}/20\n`;
improvementPrompt += `- Domain Relevance: ${Math.round(qualityMetrics.domain_relevance)}/15\n`;
improvementPrompt += `- Uniqueness: ${Math.round(qualityMetrics.uniqueness)}/20\n\n`;

improvementPrompt += 'PRIORITY IMPROVEMENTS REQUIRED:\n';
improvementStrategies.slice(0, 5).forEach((strategy, index) => {
  improvementPrompt += `${index + 1}. [${strategy.priority.toUpperCase()}] ${strategy.instruction}\n`;
});

improvementPrompt += '\nADVERSARIAL WRITING GUIDELINES:\n';
for (const [category, guidelines] of Object.entries(adversarialInstructions)) {
  improvementPrompt += `\n${category.toUpperCase().replace('_', ' ')}:\n`;
  for (const [key, instruction] of Object.entries(guidelines)) {
    improvementPrompt += `• ${instruction}\n`;
  }
}

improvementPrompt += '\n\nTARGET: Achieve 85+ overall quality score by addressing the above improvements.';
improvementPrompt += '\nREWRITE THE CONTENT COMPLETELY with these improvements in mind.';

return [{
  json: {
    content_id: contentId,
    domain: domain,
    improvement_strategies: improvementStrategies,
    adversarial_instructions: adversarialInstructions,
    improvement_prompt: improvementPrompt,
    original_quality_score: feedback.overall_score,
    target_quality_score: 85,
    feedback_analysis_complete: true
  }
}];

